solutions.python:
import math

class Solution:
    def solve(self, n: int) -> int:
        sum = 0
        for i in str(n):
            sum += int(i) ** 2
        return math.isqrt(sum)

if __name__ == '__main__':
    n = int(input())
    print(Solution().solve(n))

