#include <cmath>
#include <iostream>

int main() {
    int n;
    std::cin >> n;
    std::cout << Solution().solve(n) << std::endl;
    return 0;
}

class Solution {
public:
    int solve(int n) {
        int sum = 0;
        for (char c : std::to_string(n))
            sum += pow((c - '0'), 2);
        return sqrt(sum);
    }
};
